def yanghui(x, y):
    if y == 1 or y == x:
        return 1
    else:
        z = yanghui(x-1, y-1)+yanghui(x-1, y)  # 第x行第y个数字等于第x-1行的第y-1个数和第y个数之和。
        return z

n = int(input("请输入杨辉三角形的行数："))
